        const particles = [];
        const numParticles = 50;

        class Particle {
            constructor() {
                this.x = Math.random() * canvas.width;
                this.y = Math.random() * canvas.height;
                this.size = Math.random() * 3 + 1;
                this.speedX = Math.random() * 0.5 - 0.25;
                this.speedY = Math.random() * 0.5 - 0.25;
                this.bloomPhase = Math.random() * Math.PI * 2;
                this.bloomSpeed = 0.02 + Math.random() * 0.02;
            }

            update() {
                this.x += this.speedX;
                this.y += this.speedY;
                this.bloomPhase += this.bloomSpeed;

                if (this.x < 0) this.x = canvas.width;
                if (this.x > canvas.width) this.x = 0;
                if (this.y < 0) this.y = canvas.height;
                if (this.y > canvas.height) this.y = 0;
            }

            draw() {
                const bloom = Math.sin(this.bloomPhase) * 0.5 + 0.5;
                const alpha = bloom * 0.4;
                const hue = 330 + bloom * 30; // Pink to gold

                ctx.beginPath();
                ctx.arc(this.x, this.y, this.size * (0.5 + bloom * 0.5), 0, Math.PI * 2);
                ctx.fillStyle = `hsla(${hue}, 70%, 60%, ${alpha})`;
                ctx.fill();

                // Gentle glow
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.size * 2 * bloom, 0, Math.PI * 2);
                ctx.fillStyle = `hsla(${hue}, 70%, 70%, ${alpha * 0.3})`;
                ctx.fill();
            }
